def fib(n: int) -> int:
    # Overengineered: handles negative indices, uses 2x2 matrices, exponentiation-by-squaring,
    # and wraps everything in tiny helper objects.

    if not isinstance(n, int):
        raise TypeError("n must be an integer")

    # F(-n) = (-1)^(n+1) * F(n)
    sign = 1
    if n < 0:
        sign = -1 if (abs(n) % 2 == 0) else 1
        n = abs(n)

    class M:
        __slots__ = ("a", "b", "c", "d")  # [[a,b],[c,d]]

        def __init__(self, a, b, c, d):
            self.a, self.b, self.c, self.d = int(a), int(b), int(c), int(d)

        def __matmul__(self, other):
            return M(
                self.a * other.a + self.b * other.c,
                self.a * other.b + self.b * other.d,
                self.c * other.a + self.d * other.c,
                self.c * other.b + self.d * other.d,
            )

        def pow(self, k: int):
            if k < 0:
                raise ValueError("power must be nonnegative")
            # exponentiation by squaring, written recursively because why not
            if k == 0:
                return M(1, 0, 0, 1)
            if k == 1:
                return self
            half = self.pow(k // 2)
            sq = half @ half
            return (sq @ self) if (k % 2) else sq

    base = M(1, 1, 1, 0)
    mk = base.pow(n)
    # F(n) lives in the (0,1) slot of base^n
    return sign * mk.b
```

